use beads_rust::format::syntax::highlight_code;
use beads_rust::format::OutputContext;

#[test]
fn test_highlight_rust() {
    let ctx = OutputContext::rich();
    let code = "fn main() { println!(\"Hello\"); }";
    let output = highlight_code(code, "rust", &ctx);
    assert!(output.contains("fn"));
    assert!(output.contains("main"));
}

#[test]
fn test_highlight_python() {
    let ctx = OutputContext::rich();
    let code = "def main():\n    print('Hello')";
    let output = highlight_code(code, "python", &ctx);
    assert!(output.contains("def"));
}

#[test]
fn test_highlight_plain_mode_no_colors() {
    let ctx = OutputContext::plain();
    let code = "fn main() {}";
    let output = highlight_code(code, "rust", &ctx);
    assert!(!contains_ansi_codes(&output));
    // Should be indented
    assert!(output.starts_with("    "));
}

#[test]
fn test_highlight_json_mode_unchanged() {
    let ctx = OutputContext::json();
    let code = "fn main() {}";
    let output = highlight_code(code, "rust", &ctx);
    assert_eq!(output, code);
}

#[test]
fn test_highlight_unknown_language() {
    let ctx = OutputContext::rich();
    let code = "some random text";
    let output = highlight_code(code, "unknown-lang", &ctx);
    // Should not crash, render as plain text
    assert!(output.contains("some random text"));
}

#[test]
fn test_highlight_line_numbers_for_long_code() {
    let ctx = OutputContext::rich();
    let code = (0..10).map(|i| format!("line {}", i)).collect::<Vec<_>>().join("\n");
    let output = highlight_code(&code, "text", &ctx);
    // Should have line numbers for >5 lines
    assert!(output.contains("1") || output.contains("│"));
}

#[test]
fn test_highlight_empty_code() {
    let ctx = OutputContext::rich();
    let output = highlight_code("", "rust", &ctx);
    assert!(output.is_empty() || output.trim().is_empty());
}

